function createBridgeServer(copilotClient: AdaptedCopilotClient) {
    const port = parseInt(process.env["BRIDGE_PORT"] ?? "", 10) || DEFAULT_WS_PORT;

    const httpServer = createHttpServer();
    const wss = new WebSocketServer({ server: httpServer });

    let activeClient: ActiveClient | null = null;
    let heartbeatInterval: ReturnType<typeof setInterval> | null = null;

    // Reconnect replay buffer — son MAX_MESSAGE_BUFFER mesajı tutar
    const messageBuffer: ServerMessage[] = [];

    function getClientIP(req: IncomingMessage): string {
        const forwarded = req.headers["x-forwarded-for"];
        if (typeof forwarded === "string") {
            return forwarded.split(",")[0]?.trim() ?? "unknown";
        }
        return req.socket.remoteAddress ?? "unknown";
    }

    wss.on("connection", (ws: WebSocket, req: IncomingMessage) => {
        const clientIP = getClientIP(req);
        console.log(`[ws] Yeni bağlantı: ${clientIP}`);

        // Tek istemci kısıtlaması — eski bağlantıyı kapat
        if (activeClient !== null) {
            console.log("[ws] Mevcut bağlantı kapatılıyor (yeni istemci bağlandı)");
            activeClient.handler.cleanup();
            activeClient.ws.close(1000, "New client connected");
            activeClient = null;
        }

        // Pairing rate limit kontrolü
        if (!checkPairingRateLimit(clientIP)) {
            ws.close(1008, "Rate limit exceeded");
            return;
        }

        // JWT ile reconnect desteği (URL query'de token varsa)
        const url = new URL(req.url ?? "/", `ws://${req.headers.host ?? "localhost"}`);
        const jwtToken = url.searchParams.get("token");

        const send: (message: ServerMessage) => void = (message) => {
            // Replay buffer'a ekle (auth mesajlarını hariç tut)
            if (message.type !== "pairing.success" && message.type !== "token.refresh") {
                messageBuffer.push(message);
                if (messageBuffer.length > MAX_MESSAGE_BUFFER) {
                    messageBuffer.shift();
                }
            }
            if (ws.readyState === WebSocket.OPEN) {
                ws.send(JSON.stringify(message));
            }
        };

        const sessionManager = createSessionManager(copilotClient, send);
        const handler = createMessageHandler(sessionManager, send, messageBuffer, null);

        // JWT ile otomatik auth
        if (jwtToken !== null && handler.authenticateWithJWT(jwtToken)) {
            console.log(`[ws] JWT ile yeniden bağlanıldı: ${handler.deviceId}`);
        }

        activeClient = { ws, handler, alive: true };

        ws.on("message", async (data: Buffer) => {
            try {
                await handler.handleRawMessage(data.toString("utf-8"));
            } catch (err) {
                console.error("[ws] Mesaj işleme hatası:", err);
            }
        });

        ws.on("pong", () => {
            if (activeClient !== null && activeClient.ws === ws) {
                activeClient.alive = true;
            }
        });

        ws.on("close", (code: number, reason: Buffer) => {
            console.log(`[ws] Bağlantı kapandı: ${code} ${reason.toString("utf-8")}`);
            if (activeClient !== null && activeClient.ws === ws) {
                handler.cleanup();
                activeClient = null;
            }
        });

        ws.on("error", (err: Error) => {
            console.error("[ws] WebSocket hatası:", err.message);
        });
    });

    // Heartbeat mekanizması
    heartbeatInterval = setInterval(() => {
        if (activeClient !== null) {
            if (!activeClient.alive) {
                console.log("[ws] Heartbeat timeout — bağlantı kapatılıyor");
                activeClient.handler.cleanup();
                activeClient.ws.terminate();
                activeClient = null;
                return;
            }
            activeClient.alive = false;
            activeClient.ws.ping();
        }
    }, HEARTBEAT_INTERVAL_MS);

    return {
        start(): Promise<void> {
            return new Promise((resolve) => {
                httpServer.listen(port, () => {
                    console.log(`[ws] Bridge server dinliyor: ws://0.0.0.0:${port}`);
                    resolve();
                });
            });
        },

        async shutdown(): Promise<void> {
            console.log("[ws] Server kapatılıyor...");

            if (heartbeatInterval !== null) {
                clearInterval(heartbeatInterval);
            }

            if (activeClient !== null) {
                activeClient.handler.cleanup();
                activeClient.ws.close(1001, "Server shutting down");
                activeClient = null;
            }

            wss.close();

            return new Promise((resolve) => {
                httpServer.close(() => {
                    console.log("[ws] Server kapatıldı");
                    resolve();
                });
            });
        },

        get port() {
            return port;
        },

        get hasClient() {
            return activeClient !== null;
        },
    };
}

