function connectToURL(url: string): void {
        cleanup();
        setState("connecting");

        try {
            ws = new WebSocket(url);
        } catch (err) {
            config.onError(`Bağlantı hatası: ${String(err)}`);
            setState("disconnected");
            return;
        }

        ws.onopen = () => {
            setState("connected");
        };

        ws.onmessage = (event) => {
            handleMessage(String(event.data));
        };

        ws.onclose = (event) => {
            setState("disconnected");
            cleanup();
            if (event.code !== 1000) {
                scheduleReconnect();
            }
        };

        ws.onerror = () => {
            config.onError("WebSocket bağlantı hatası");
        };
    }

