// Tarihe göre gruplandırma
type DateGroup = {
    label: string;
    sessions: ReadonlyArray<SessionInfo>;
};

function groupByDate(
    sessions: ReadonlyArray<SessionInfo>
): ReadonlyArray<DateGroup> {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayMs = today.getTime();
    const yesterdayMs = todayMs - 86400000;
    const weekMs = todayMs - 7 * 86400000;

    const todayItems: Array<SessionInfo> = [];
    const yesterdayItems: Array<SessionInfo> = [];
    const weekItems: Array<SessionInfo> = [];
    const olderItems: Array<SessionInfo> = [];

    for (const session of sessions) {
        if (session.lastActiveAt >= todayMs) {
            todayItems.push(session);
        } else if (session.lastActiveAt >= yesterdayMs) {
            yesterdayItems.push(session);
        } else if (session.lastActiveAt >= weekMs) {
            weekItems.push(session);
        } else {
            olderItems.push(session);
        }
    }

    const result: Array<DateGroup> = [];
    if (todayItems.length > 0) {
        result.push({ label: "Bugün", sessions: todayItems });
    }
    if (yesterdayItems.length > 0) {
        result.push({ label: "Dün", sessions: yesterdayItems });
    }
    if (weekItems.length > 0) {
        result.push({ label: "Son 7 Gün", sessions: weekItems });
    }
    if (olderItems.length > 0) {
        result.push({ label: "Daha Eski", sessions: olderItems });
    }

    return result;
}

function formatSessionTitle(session: SessionInfo): string {
    if (session.summary !== undefined && session.summary.trim().length > 0) {
        return session.summary;
    }

    if (session.context?.repository !== undefined) {
        return session.context.repository;
    }

    if (session.context?.cwd !== undefined) {
        const pathParts = session.context.cwd.split(/[\\/]/).filter(Boolean);
        return pathParts[pathParts.length - 1] ?? session.id;
    }

    return session.id;
}

function formatSessionPreview(session: SessionInfo): string {
    const previewParts = [
        session.context?.branch,
        session.context?.cwd,
        session.model !== "unknown" ? session.model : null,
    ].filter((value): value is string => value !== undefined && value !== null && value.length > 0);

    return previewParts.join(" • ");
}

