import {
    View,
    TextInput,
    Pressable,
    Text,
    StyleSheet,
    Platform,
} from "react-native";

type Props = {
    onSend: (content: string) => void;
    onAbort: () => void;
    isTyping: boolean;
    disabled: boolean;
};

function ChatInput({ onSend, onAbort, isTyping, disabled }: Props) {
    const [input, setInput] = useState("");

    const handleSend = useCallback(() => {
        const trimmed = input.trim();
        if (trimmed.length === 0 || disabled) return;
        setInput("");
        onSend(trimmed);
    }, [input, disabled, onSend]);

    const canSend = input.trim().length > 0 && !disabled;

    return (
        <View style={styles.container}>
            <View style={styles.inputRow}>
                <TextInput
                    style={styles.textInput}
                    value={input}
                    onChangeText={setInput}
                    placeholder="Mesajınızı yazın..."
                    placeholderTextColor="#5a5a5a"
                    multiline
                    maxLength={10000}
                    returnKeyType="send"
                    onSubmitEditing={handleSend}
                    blurOnSubmit={false}
                    editable={!disabled}
                />
                {isTyping ? (
                    <Pressable
                        style={styles.abortButton}
                        onPress={onAbort}
                        hitSlop={8}
                    >
                        <View style={styles.abortIcon} />
                    </Pressable>
                ) : (
                    <Pressable
                        style={[
                            styles.sendButton,
                            !canSend && styles.sendButtonDisabled,
                        ]}
                        onPress={handleSend}
                        disabled={!canSend}
                        hitSlop={8}
                    >
                        <Text style={styles.sendIcon}>↑</Text>
                    </Pressable>
                )}
            </View>
        </View>
    );
}

const styles = StyleSheet.create({
    container: {
        paddingHorizontal: 12,
        paddingTop: 6,
        paddingBottom: Platform.OS === "ios" ? 4 : 8,
        backgroundColor: "#1a1a1a",
        borderTopWidth: 1,
        borderTopColor: "#2a2a2a",
    },
    inputRow: {
        flexDirection: "row",
        alignItems: "flex-end",
        backgroundColor: "#242424",
        borderRadius: 24,
        borderWidth: 1,
        borderColor: "#333333",
        paddingLeft: 16,
        paddingRight: 6,
        paddingVertical: 4,
    },
    textInput: {
        flex: 1,
        fontSize: 15,
        color: "#e4e4e4",
        maxHeight: 120,
        minHeight: 36,
        paddingVertical: Platform.OS === "ios" ? 8 : 6,
        textAlignVertical: "center",
    },
    sendButton: {
        width: 32,
        height: 32,
        borderRadius: 16,
        backgroundColor: "#0078d4",
        justifyContent: "center",
        alignItems: "center",
        marginBottom: 2,
        marginLeft: 6,
    },
    sendButtonDisabled: {
        backgroundColor: "#333333",
    },
    sendIcon: {
        color: "#ffffff",
        fontSize: 18,
        fontWeight: "700",
        marginTop: -1,
    },
    abortButton: {
        width: 32,
        height: 32,
        borderRadius: 16,
        backgroundColor: "#f14c4c",
        justifyContent: "center",
        alignItems: "center",
        marginBottom: 2,
        marginLeft: 6,
    },
    abortIcon: {
        width: 10,
        height: 10,
        borderRadius: 2,
        backgroundColor: "#ffffff",
    },
});

handleSend = useCallback(() => {
        const trimmed = input.trim();
        if (trimmed.length === 0 || disabled) return;
        setInput("");
        onSend(trimmed);
    }, [input, disabled, onSend])

() => {
        const trimmed = input.trim();
        if (trimmed.length === 0 || disabled) return;
        setInput("");
        onSend(trimmed);
    }

function rejectPendingMessages(errorMessage: string): void {
        while (pendingMessages.length > 0) {
            const pending = pendingMessages.shift();
            if (pending !== undefined) {
                clearTimeout(pending.timeoutId);
                pending.reject(new Error(errorMessage));
            }
        }
    }

function disconnectWithError(errorMessage: string): void {
        jwt = null;
        serverUrl = null;
        expectedFingerprint = null;
        lastServerSeq = 0;
        reconnectAttempt = 0;
        cleanup();
        setState("disconnected");
        rejectPendingMessages(errorMessage);
        config.onError(errorMessage);
    }

function scheduleReconnect(): void {
        if (reconnectTimer !== null || state === "connecting") return;
        if (jwt === null || serverUrl === null) return;

        const delay = Math.min(
            BASE_RECONNECT_DELAY_MS * Math.pow(2, reconnectAttempt),
            MAX_RECONNECT_DELAY_MS
        );
        reconnectAttempt += 1;

        reconnectTimer = setTimeout(() => {
            reconnectTimer = null;
            if (jwt !== null) {
                connectWithJWT(jwt);
            }
        }, delay);
    }

function handleMessage(data: string): void {
        let parsed: unknown;

        try {
            parsed = JSON.parse(data);
        } catch {
            config.onError("Geçersiz mesaj formatı");
            return;
        }

        const result = serverMessageSchema.safeParse(parsed);
        if (!result.success) {
            config.onError("Sunucudan geçersiz şema ile mesaj geldi");
            return;
        }

        const message = result.data as ServerMessage;
        lastServerSeq = message.seq;

        if (message.type === "pairing.success") {
            if (
                expectedFingerprint !== null &&
                message.payload.certFingerprint !== expectedFingerprint
            ) {
                disconnectWithError(
                    "Sertifika doğrulaması başarısız — sunucu güvenilir değil"
                );
                return;
            }

            jwt = message.payload.jwt;
            setState("authenticated");
            reconnectAttempt = 0;
            flushPending();
        }

        if (message.type === "token.refresh") {
            jwt = message.payload.jwt;
        }

        config.onMessage(message);
    }

function ScanScreen() {
    const router = useRouter();
    const [permission, requestPermission] = useCameraPermissions();
    const [scanned, setScanned] = useState(false);
    const [isPairing, setIsPairing] = useState(false);
    const hasShownErrorRef = useRef(false);
    const connectionState = useConnectionStore((s) => s.state);
    const connectionError = useConnectionStore((s) => s.error);

    useEffect(() => {
        if (connectionState === "authenticated") {
            router.replace("/");
        }
    }, [connectionState, router]);

    useEffect(() => {
        if (connectionError === null || hasShownErrorRef.current) {
            return;
        }

        hasShownErrorRef.current = true;
        setIsPairing(false);
        setScanned(false);

        Alert.alert("Bağlantı Hatası", connectionError, [
            {
                text: "Tekrar Dene",
                onPress: () => {
                    hasShownErrorRef.current = false;
                },
            },
        ]);
    }, [connectionError]);

    function handleBarCodeScanned(result: { data: string }): void {
        if (scanned) return;
        setScanned(true);

        try {
            const parsed: unknown = JSON.parse(result.data);
            const qrPayloadResult = qrPayloadSchema.safeParse(parsed);

            if (!qrPayloadResult.success) {
                Alert.alert("Geçersiz QR Kod", "Bu QR kod Copilot Mobile bridge'e ait değil.", [
                    { text: "Tekrar Dene", onPress: () => setScanned(false) },
                ]);
                return;
            }

            hasShownErrorRef.current = false;
            setIsPairing(true);
            connectWithQR(qrPayloadResult.data);
        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : "QR kod okunamadı.";
            Alert.alert("QR Kod Hatası", "QR kod okunamadı.", [
                {
                    text: "Tekrar Dene",
                    onPress: () => {
                        setIsPairing(false);
                        setScanned(false);
                    },
                },
            ]);
            console.warn("QR tarama hatası:", errorMessage);
        }
    }

    if (permission === null) {
        return (
            <View style={styles.container}>
                <Text style={styles.text}>Kamera izni kontrol ediliyor...</Text>
            </View>
        );
    }

    if (!permission.granted) {
        return (
            <View style={styles.container}>
                <Text style={styles.text}>Kamera izni gerekli</Text>
                <Text style={styles.subtext}>
                    QR kod taramak için kamera erişimi vermeniz gerekiyor.
                </Text>
                <Pressable style={styles.button} onPress={requestPermission}>
                    <Text style={styles.buttonText}>İzin Ver</Text>
                </Pressable>
            </View>
        );
    }

    return (
        <View style={styles.container}>
            <CameraView
                style={styles.camera}
                facing="back"
                barcodeScannerSettings={{
                    barcodeTypes: ["qr"],
                }}
                onBarcodeScanned={scanned ? undefined : handleBarCodeScanned}
            />

            <View style={styles.overlay}>
                <View style={styles.scanFrame} />
                <Text style={styles.instructions}>
                    {isPairing
                        ? "Bridge sunucusuna bağlanılıyor..."
                        : "Bridge sunucusundaki QR kodu tarayın"}
                </Text>
            </View>

            {scanned && !isPairing && (
                <View style={styles.rescanContainer}>
                    <Pressable
                        style={styles.button}
                        onPress={() => setScanned(false)}
                    >
                        <Text style={styles.buttonText}>Tekrar Tara</Text>
                    </Pressable>
                </View>
            )}
        </View>
    );
}

async function main(): Promise<void> {
    console.log("Copilot Mobile Bridge başlatılıyor...\n");

    // Copilot SDK adapter oluştur
    const copilotClient = createCopilotAdapter();

    // SDK erişilebilirliğini kontrol et
    const available = await copilotClient.isAvailable();
    if (!available) {
        console.warn("[copilot] Copilot CLI erişilemedi. GitHub hesabınızla oturum açtığınızdan emin olun.");
        console.warn("[copilot] Bridge server yine de başlatılıyor (bağlantı denemesi devam edecek)...\n");
    } else {
        console.log("[copilot] Copilot CLI bağlantısı başarılı\n");
    }

    // WebSocket sunucu başlat
    const wsServer = createBridgeServer(copilotClient);
    await wsServer.start();

    // QR kodu göster
    await displayQRCode(wsServer.port);

    // Graceful shutdown
    const shutdown = async () => {
        console.log("\nKapatılıyor...");
        await wsServer.shutdown();
        await copilotClient.shutdown();
        process.exit(0);
    };

    process.on("SIGINT", shutdown);
    process.on("SIGTERM", shutdown);
}

