nodes.content:
import type {
    ServerMessage,
    ClientMessage,
    QRPayload,
} from "@copilot-mobile/shared";

type WSClientConfig = {
    onMessage: (message: ServerMessage) => void;
    onStateChange: (state: ConnectionState) => void;
    onError: (error: string) => void;
};

type PendingMessage = {
    message: ClientMessage;
    resolve: () => void;
    reject: (error: Error) => void;
    timeoutId: ReturnType<typeof setTimeout>;
};

function nextSeq(): number {
    seqCounter += 1;
    return seqCounter;
}

function generateId(): string {
    if (typeof Crypto.randomUUID === "function") {
        return Crypto.randomUUID();
    }

    const bytes = Crypto.getRandomValues(new Uint8Array(16));
    bytes[6] = (bytes[6]! & 0x0f) | 0x40;
    bytes[8] = (bytes[8]! & 0x3f) | 0x80;

    const hex = Array.from(bytes, (byte) => byte.toString(16).padStart(2, "0"));

    return [
        hex.slice(0, 4).join(""),
        hex.slice(4, 6).join(""),
        hex.slice(6, 8).join(""),
        hex.slice(8, 10).join(""),
        hex.slice(10, 16).join(""),
    ].join("-");
}

function createWSClient(config: WSClientConfig) {
    let ws: WebSocket | null = null;
    let state: ConnectionState = "disconnected";
    let jwt: string | null = null;
    let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
    const pendingMessages: Array<PendingMessage> = [];
    let reconnectAttempt = 0;
    let serverUrl: string | null = null;
    let expectedFingerprint: string | null = null;
    let lastServerSeq = 0;
    const MAX_RECONNECT_DELAY_MS = 30_000;
    const BASE_RECONNECT_DELAY_MS = 1_000;

    function setState(next: ConnectionState): void {
        if (state === next) return;
        state = next;
        config.onStateChange(next);
    }

    function cleanup(): void {
        if (reconnectTimer !== null) {
            clearTimeout(reconnectTimer);
            reconnectTimer = null;
        }
        if (ws !== null) {
            ws.onopen = null;
            ws.onclose = null;
            ws.onmessage = null;
            ws.onerror = null;
            ws.close();
            ws = null;
        }
    }

    function buildMessage(
        type: ClientMessage["type"],
        payload: Record<string, unknown>
    ): ClientMessage {
        return {
            id: generateId(),
            timestamp: Date.now(),
            seq: nextSeq(),
            type,
            payload,
        } as ClientMessage;
    }

    function sendRaw(message: ClientMessage): void {
        if (ws !== null && ws.readyState === WebSocket.OPEN) {
            ws.send(JSON.stringify(message));
        }
    }

    function flushPending(): void {
        while (pendingMessages.length > 0) {
            const pending = pendingMessages.shift();
            if (pending !== undefined) {
                sendRaw(pending.message);
                pending.resolve();
            }
        }
    }

    function send(message: ClientMessage): Promise<void> {
        if (state === "authenticated" && ws !== null && ws.readyState === WebSocket.OPEN) {
            sendRaw(message);
            return Promise.resolve();
        }
        return new Promise<void>((resolve, reject) => {
            const timeoutId = setTimeout(() => {
                const idx = pendingMessages.findIndex((p) => p.message === message);
                if (idx !== -1) {
                    pendingMessages.splice(idx, 1);
                    reject(new Error("Mesaj gönderme zaman aşımına uğradı"));
                }
            }, PENDING_TIMEOUT_MS);
            pendingMessages.push({
                message,
                resolve: () => { clearTimeout(timeoutId); resolve(); },
                reject: (err: Error) => { clearTimeout(timeoutId); reject(err); },
                timeoutId,
            });
        });
    }

    function rejectPendingMessages(errorMessage: string): void {
        while (pendingMessages.length > 0) {
            const pending = pendingMessages.shift();
            if (pending !== undefined) {
                clearTimeout(pending.timeoutId);
                pending.reject(new Error(errorMessage));
            }
        }
    }

    function disconnectWithError(errorMessage: string): void {
        jwt = null;
        serverUrl = null;
        expectedFingerprint = null;
        lastServerSeq = 0;
        reconnectAttempt = 0;
        cleanup();
        setState("disconnected");
        rejectPendingMessages(errorMessage);
        config.onError(errorMessage);
    }

    function scheduleReconnect(): void {
        if (reconnectTimer !== null || state === "connecting") return;
        if (jwt === null || serverUrl === null) return;

        const delay = Math.min(
            BASE_RECONNECT_DELAY_MS * Math.pow(2, reconnectAttempt),
            MAX_RECONNECT_DELAY_MS
        );
        reconnectAttempt += 1;

        reconnectTimer = setTimeout(() => {
            reconnectTimer = null;
            if (jwt !== null) {
                connectWithJWT(jwt);
            }
        }, delay);
    }

    function handleMessage(data: string): void {
        let parsed: unknown;

        try {
            parsed = JSON.parse(data);
        } catch {
            config.onError("Geçersiz mesaj formatı");
            return;
        }

        const result = serverMessageSchema.safeParse(parsed);
        if (!result.success) {
            config.onError("Sunucudan geçersiz şema ile mesaj geldi");
            return;
        }

        const message = result.data as ServerMessage;
        lastServerSeq = message.seq;

        if (message.type === "pairing.success") {
            if (
                expectedFingerprint !== null &&
                message.payload.certFingerprint !== expectedFingerprint
            ) {
                disconnectWithError(
                    "Sertifika doğrulaması başarısız — sunucu güvenilir değil"
                );
                return;
            }

            jwt = message.payload.jwt;
            setState("authenticated");
            reconnectAttempt = 0;
            flushPending();
        }

        if (message.type === "token.refresh") {
            jwt = message.payload.jwt;
        }

        config.onMessage(message);
    }

    function connectToURL(url: string): void {
        cleanup();
        setState("connecting");

        try {
            ws = new WebSocket(url);
        } catch (err) {
            config.onError(`Bağlantı hatası: ${String(err)}`);
            setState("disconnected");
            return;
        }

        ws.onopen = () => {
            setState("connected");
        };

        ws.onmessage = (event) => {
            handleMessage(String(event.data));
        };

        ws.onclose = (event) => {
            setState("disconnected");
            cleanup();
            if (event.code !== 1000) {
                scheduleReconnect();
            }
        };

        ws.onerror = () => {
            config.onError("WebSocket bağlantı hatası");
        };
    }

    function connectWithQR(qrPayload: QRPayload): void {
        serverUrl = qrPayload.url;
        expectedFingerprint = qrPayload.certFingerprint;
        lastServerSeq = 0;
        connectToURL(serverUrl);

        // Bağlantı açıldığında pairing token gönder
        const originalOnOpen = ws?.onopen;
        if (ws !== null) {
            ws.onopen = (event) => {
                if (originalOnOpen !== null && originalOnOpen !== undefined) {
                    (originalOnOpen as (event: Event) => void)(event);
                }
                const pairMsg = buildMessage("auth.pair", {
                    pairingToken: qrPayload.token,
                });
                sendRaw(pairMsg);
            };
        }
    }

    function connectWithJWT(token: string): void {
        jwt = token;
        if (serverUrl === null) {
            config.onError("Sunucu URL'i bilinmiyor — QR kodla yeniden bağlanın");
            return;
        }

        const authenticatedUrl = new URL(serverUrl);
        authenticatedUrl.searchParams.set("token", token);

        connectToURL(authenticatedUrl.toString());
        const originalOnOpen = ws?.onopen;
        if (ws !== null) {
            ws.onopen = (event) => {
                if (originalOnOpen !== null && originalOnOpen !== undefined) {
                    (originalOnOpen as (event: Event) => void)(event);
                }
                const reconnMsg = buildMessage("reconnect", { lastSeenSeq: lastServerSeq });
                sendRaw(reconnMsg);
            };
        }
    }

    return {
        connectWithQR,

        connectWithJWT,

        send,

        sendMessage(type: ClientMessage["type"], payload: Record<string, unknown>): Promise<void> {
            const msg = buildMessage(type, payload);
            return send(msg);
        },

        disconnect(): void {
            jwt = null;
            serverUrl = null;
            expectedFingerprint = null;
            lastServerSeq = 0;
            reconnectAttempt = 0;
            cleanup();
            setState("disconnected");
            rejectPendingMessages("Bağlantı kapatıldı");
        },

        getState(): ConnectionState {
            return state;
        },

        getJWT(): string | null {
            return jwt;
        },

        setJWT(token: string): void {
            jwt = token;
        },
    };
}

function setState(next: ConnectionState): void {
        if (state === next) return;
        state = next;
        config.onStateChange(next);
    }

function cleanup(): void {
        if (reconnectTimer !== null) {
            clearTimeout(reconnectTimer);
            reconnectTimer = null;
        }
        if (ws !== null) {
            ws.onopen = null;
            ws.onclose = null;
            ws.onmessage = null;
            ws.onerror = null;
            ws.close();
            ws = null;
        }
    }

function buildMessage(
        type: ClientMessage["type"],
        payload: Record<string, unknown>
    ): ClientMessage {
        return {
            id: generateId(),
            timestamp: Date.now(),
            seq: nextSeq(),
