// Bridge servis — WebSocket istemcisi ve mesaj yönlendiriciyi birleştirir
// Tüm bridge iletişimi bu modül üzerinden yapılır
import type { QRPayload, SessionConfig, ClientMessage } from "@copilot-mobile/shared";

function getClient(): ReturnType<typeof createWSClient> {
    if (client === null) {
        client = createWSClient({
            onMessage: handleServerMessage,
            onStateChange: (state: ConnectionState) => {
                useConnectionStore.getState().setState(state);
            },
            onError: (error: string) => {
                useConnectionStore.getState().setError(error);
            },
        });
    }
    return client;
}

function connectWithQR(qrPayload: QRPayload): void {
    const c = getClient();
    const connStore = useConnectionStore.getState();
    connStore.setError(null);
    connStore.setServerInfo(qrPayload.url, qrPayload.certFingerprint);
    c.connectWithQR(qrPayload);
}

async function createSession(config: SessionConfig): Promise<void> {
    const c = getClient();
    useConnectionStore.getState().setError(null);
    await c.sendMessage("session.create", { config });
}

async function sendMessageWithoutLocalEcho(sessionId: string, content: string): Promise<void> {
    const c = getClient();

    try {
        await c.sendMessage("message.send", { sessionId, content });
    } catch (error) {
        useSessionStore.getState().setAssistantTyping(false);
        useConnectionStore.getState().setError(
            `Mesaj gönderilemedi: ${error instanceof Error ? error.message : String(error)}`
        );
    }
}

async function sendMessage(sessionId: string, content: string): Promise<void> {
    const sessionStore = useSessionStore.getState();
    sessionStore.addUserMessage(content);
    sessionStore.setAssistantTyping(true);
    await sendMessageWithoutLocalEcho(sessionId, content);
}

async function sendQueuedMessage(sessionId: string, content: string): Promise<void> {
    const sessionStore = useSessionStore.getState();
    sessionStore.setAssistantTyping(true);
    await sendMessageWithoutLocalEcho(sessionId, content);
}

async function abortMessage(sessionId: string): Promise<void> {
    const c = getClient();
    await c.sendMessage("message.abort", { sessionId });
}

async function respondPermission(requestId: string, approved: boolean): Promise<void> {
    const c = getClient();
    const sessionStore = useSessionStore.getState();
    sessionStore.setPermissionPrompt(null);
    await c.sendMessage("permission.respond", { requestId, approved });
}

async function respondUserInput(requestId: string, value: string): Promise<void> {
    const c = getClient();
    const sessionStore = useSessionStore.getState();
    sessionStore.setUserInputPrompt(null);
    await c.sendMessage("user_input.respond", { requestId, value });
}

async function listSessions(): Promise<void> {
    const c = getClient();
    await c.sendMessage("session.list", {});
}

async function deleteSession(sessionId: string): Promise<void> {
    const c = getClient();
    await c.sendMessage("session.delete", { sessionId });
}

async function resumeSession(sessionId: string): Promise<void> {
    const c = getClient();
    useConnectionStore.getState().setError(null);
    await c.sendMessage("session.resume", { sessionId });
}

async function listModels(): Promise<void> {
    const c = getClient();
    await c.sendMessage("models.request", {});
}

function disconnect(): void {
    if (client !== null) {
        client.disconnect();
        client = null;
    }
    useConnectionStore.getState().reset();
    useSessionStore.getState().reset();
}

