    SessionHistoryItem,
    ModelInfo,
    PermissionKind,
} from "@copilot-mobile/shared";

type SessionRecord = {
    session: AdaptedCopilotSession;
    info: SessionInfo;
    unsubscribes: Array<() => void>;
};

function adaptSessionContext(metadata: SessionMetadata): SessionInfo["context"] {
    const context = metadata.context;

    if (context === undefined) {
        return undefined;
    }

    return {
        cwd: context.cwd,
        ...(context.gitRoot !== undefined ? { gitRoot: context.gitRoot } : {}),
        ...(context.repository !== undefined ? { repository: context.repository } : {}),
        ...(context.branch !== undefined ? { branch: context.branch } : {}),
    };
}

function adaptSessionInfoFromMetadata(metadata: SessionMetadata): SessionInfo {
    const context = adaptSessionContext(metadata);

    return {
        id: metadata.sessionId,
        model: "unknown",
        createdAt: metadata.startTime.getTime(),
        lastActiveAt: metadata.modifiedTime.getTime(),
        status: "idle",
        ...(metadata.summary !== undefined ? { summary: metadata.summary } : {}),
        ...(context !== undefined ? { context } : {}),
    };
}

function parseEventTimestamp(timestamp: string): number {
    const parsed = Date.parse(timestamp);
    return Number.isNaN(parsed) ? Date.now() : parsed;
}

function normalizeSessionHistory(
    events: ReadonlyArray<SessionEvent>
): Array<SessionHistoryItem> {
    const items: Array<SessionHistoryItem> = [];
    const toolIndexByRequestId = new Map<string, number>();

    for (const event of events) {
        const timestamp = parseEventTimestamp(event.timestamp);

        switch (event.type) {
            case "user.message":
                items.push({
                    id: event.id,
                    timestamp,
                    type: "user",
                    content: event.data.content,
                });
                break;

            case "assistant.reasoning":
                items.push({
                    id: event.data.reasoningId,
                    timestamp,
                    type: "thinking",
                    content: event.data.content,
                });
                break;

            case "assistant.message":
                items.push({
                    id: event.data.messageId,
                    timestamp,
                    type: "assistant",
                    content: event.data.content,
                });
                break;

            case "tool.execution_start": {
                const nextIndex = items.length;
                toolIndexByRequestId.set(event.data.toolCallId, nextIndex);
                items.push({
                    id: event.id,
                    timestamp,
                    type: "tool",
                    toolName: event.data.toolName,
                    requestId: event.data.toolCallId,
                    status: "running",
                });
                break;
            }

            case "tool.execution_complete": {
                const existingIndex = toolIndexByRequestId.get(event.data.toolCallId);

                if (existingIndex !== undefined) {
                    const existingItem = items[existingIndex];

                    if (existingItem !== undefined && existingItem.type === "tool") {
                        items[existingIndex] = {
                            ...existingItem,
                            timestamp,
                            status: event.data.success ? "completed" : "failed",
                        };
                        break;
                    }
                }

                items.push({
                    id: event.id,
                    timestamp,
                    type: "tool",
                    toolName: "Tool",
                    requestId: event.data.toolCallId,
                    status: event.data.success ? "completed" : "failed",
                });
                break;
            }

            default:
                break;
        }
    }

    return items;
}

function sendError(code: string, message: string, retry: boolean): void {
        send({
            ...makeBase(),
            type: "error",
            payload: { code, message, retry },
        });
    }

handleSend = useCallback(
        (content: string) => {
            const historyStore = useChatHistoryStore.getState();
            const previousActiveConversationId = historyStore.activeConversationId;
            const activeConversationId =
                previousActiveConversationId ?? historyStore.createConversation(null);
            const conversation = previousActiveConversationId === null
                ? undefined
                : historyStore.conversations.find(
                    (item) => item.id === previousActiveConversationId
                );
            const shouldUpdateConversation =
                previousActiveConversationId === null ||
                (conversation !== undefined && conversation.title === "Yeni Sohbet");

            if (shouldUpdateConversation) {
                const title =
                    content.length > 40
                        ? content.slice(0, 40) + "..."
                        : content;
                historyStore.updateConversation(activeConversationId, title, content);
            }

            if (activeSessionId === null) {
                const store = useSessionStore.getState();
                const requestedModel = models.some((model) => model.id === selectedModel)
                    ? selectedModel
                    : models[0]?.id ?? selectedModel;
                store.addUserMessage(content);
                store.setSessionLoading(true);
                queuedMessagesRef.current = [...queuedMessagesRef.current, content];

                if (!sessionRequestInFlightRef.current) {
                    sessionRequestInFlightRef.current = true;
                    void createSession({
                        model: requestedModel,
                        reasoningEffort,
                        streaming: true,
                    }).catch(() => {
                        sessionRequestInFlightRef.current = false;
                    });
                }
                return;
            }

            sendMessage(activeSessionId, content);
        },
        [activeSessionId, models, selectedModel, reasoningEffort]
    )

