function wireSessionEvents(session: AdaptedCopilotSession): void {
        const sessionId = session.id;

        session.onMessage((content) => {
            send({
                ...makeBase(),
                type: "assistant.message",
                payload: { sessionId, content },
            });
        });

        session.onDelta((delta, index) => {
            send({
                ...makeBase(),
                type: "assistant.message_delta",
                payload: { sessionId, delta, index },
            });
        });

        session.onReasoning((content) => {
            send({
                ...makeBase(),
                type: "assistant.reasoning",
                payload: { sessionId, content },
            });
        });

        session.onReasoningDelta((delta, index) => {
            send({
                ...makeBase(),
                type: "assistant.reasoning_delta",
                payload: { sessionId, delta, index },
            });
        });

        session.onToolStart((toolName, requestId) => {
            send({
                ...makeBase(),
                type: "tool.execution_start",
                payload: { sessionId, toolName, requestId },
            });
        });

        session.onToolComplete((toolName, requestId, success) => {
