type JWTPayload = {
    deviceId: string;
    pairedAt: number;
};

function rotateSecretIfNeeded(): boolean {
    const now = Date.now();
    if (now - lastRotationAt < JWT_SECRET_ROTATION_MS) return false;

    previousSecret = currentSecret;
    previousSecretExpiresAt = now + JWT_SECRET_GRACE_MS;
    currentSecret = randomBytes(32);
    lastRotationAt = now;
    console.log("[jwt] Secret rotasyonu yapıldı");
    return true;
}

function createJWT(deviceId: string): string {
    rotateSecretIfNeeded();
    const payload: JWTPayload = {
        deviceId,
        pairedAt: Date.now(),
    };

    return jwt.sign(payload, currentSecret, {
        expiresIn: JWT_TTL_SECONDS,
        algorithm: "HS256",
    });
}

function verifyJWT(token: string): JWTPayload {
    // Önce aktif secret ile dene
    try {
        const decoded = jwt.verify(token, currentSecret, {
            algorithms: ["HS256"],
        });
        if (typeof decoded === "string" || decoded === null) {
            throw new Error("Invalid JWT payload");
        }
        return decoded as JWTPayload;
    } catch (primaryError) {
        // Grace period içinde eski secret ile dene
        if (previousSecret !== null && Date.now() < previousSecretExpiresAt) {
            const decoded = jwt.verify(token, previousSecret, {
                algorithms: ["HS256"],
            });
            if (typeof decoded === "string" || decoded === null) {
                throw new Error("Invalid JWT payload");
            }
            return decoded as JWTPayload;
        }
        throw primaryError;
    }
}

function resetJWTState(): void {
    currentSecret = getOrCreateJWTSecret();
    previousSecret = null;
    lastRotationAt = Date.now();
    previousSecretExpiresAt = 0;
}

type PairingToken = {
    token: string;
    createdAt: number;
    used: boolean;
};

function generatePairingToken(): string {
    const token = randomBytes(PAIRING_TOKEN_BYTES).toString("hex");
    activePairingToken = {
        token,
        createdAt: Date.now(),
        used: false,
    };
    return token;
}

function validatePairingToken(token: string): boolean {
    if (activePairingToken === null) return false;
    if (activePairingToken.used) return false;
    if (activePairingToken.token !== token) return false;

    const elapsed = Date.now() - activePairingToken.createdAt;
    if (elapsed > PAIRING_TOKEN_TTL_MS) {
        activePairingToken = null;
        return false;
    }

    // Tek kullanımlık — kullanıldı olarak işaretle
    activePairingToken.used = true;
    return true;
}

function isPairingActive(): boolean {
    if (activePairingToken === null) return false;
    if (activePairingToken.used) return false;
    const elapsed = Date.now() - activePairingToken.createdAt;
    return elapsed <= PAIRING_TOKEN_TTL_MS;
}

