nodes.content:
import {
    CONFIG_DIR_NAME,
    CERT_FILENAME,
    KEY_FILENAME,
    JWT_SECRET_FILENAME,
} from "@copilot-mobile/shared";

function getConfigDir(): string {
    const dir = join(homedir(), CONFIG_DIR_NAME);
    if (!existsSync(dir)) {
        mkdirSync(dir, { mode: 0o700, recursive: true });
    }
    return dir;
}

function getOrCreateJWTSecret(): Buffer {
    const configDir = getConfigDir();
    const secretPath = join(configDir, JWT_SECRET_FILENAME);

    if (existsSync(secretPath)) {
        return readFileSync(secretPath);
    }

    const secret = randomBytes(32);
    writeFileSync(secretPath, secret, { mode: 0o600 });
    return secret;
}

// --- TLS Sertifikası ---
type TLSCredentials = {
    cert: string;
    key: string;
    fingerprint: string;
};

function getOrCreateTLSCredentials(): TLSCredentials {
    const configDir = getConfigDir();
    const certPath = join(configDir, CERT_FILENAME);
    const keyPath = join(configDir, KEY_FILENAME);

    if (existsSync(certPath) && existsSync(keyPath)) {
        const cert = readFileSync(certPath, "utf-8");
        const key = readFileSync(keyPath, "utf-8");
        const fingerprint = computeCertFingerprint(cert);
        return { cert, key, fingerprint };
    }

    // openssl zorunlu — node:crypto ile geçerli X.509 sertifika üretilemez
    setupTLSWithOpenSSL(configDir);

    const cert = readFileSync(certPath, "utf-8");
    const key = readFileSync(keyPath, "utf-8");
    const fingerprint = computeCertFingerprint(cert);
    return { cert, key, fingerprint };
}

function setupTLSWithOpenSSL(configDir: string): void {
    const certPath = join(configDir, CERT_FILENAME);
    const keyPath = join(configDir, KEY_FILENAME);

    if (existsSync(certPath) && existsSync(keyPath)) return;

    if (!existsSync(configDir)) {
        mkdirSync(configDir, { mode: 0o700, recursive: true });
    }

    // execFileSync kullanarak shell injection engellenir
    execFileSync("openssl", [
        "req", "-x509",
        "-newkey", "rsa:2048",
        "-keyout", keyPath,
        "-out", certPath,
        "-days", "365",
        "-nodes",
        "-subj", "/CN=copilot-mobile-bridge",
    ], { stdio: "ignore" });
    chmodSync(keyPath, 0o600);
}

function getLocalIPs(): ReadonlyArray<string> {
    const nets = networkInterfaces();
    const results: string[] = [];

    for (const name in nets) {
        const interfaces = nets[name];
        if (interfaces === undefined) continue;

        for (const iface of interfaces) {
            // IPv4, harici (internal olmayan) adresleri filtrele
            if (iface.family === "IPv4" && !iface.internal) {
                results.push(iface.address);
            }
        }
    }

    return results;
}

function getPreferredLocalIP(): string {
    const ips = getLocalIPs();
    // 192.168.x.x tercih et, yoksa ilk adresi dön
    const preferred = ips.find((ip) => ip.startsWith("192.168."));
    if (preferred !== undefined) return preferred;
    if (ips.length > 0) return ips[0]!;
    return "127.0.0.1";
}

function nextSeq(): number {
    seqCounter += 1;
    return seqCounter;
}

