// Rate limiter — sliding window counter pattern
import {
    RATE_LIMIT_PAIRING_MAX,
    RATE_LIMIT_PAIRING_WINDOW_MS,
    RATE_LIMIT_MESSAGE_MAX,
    RATE_LIMIT_MESSAGE_WINDOW_MS,
    REPLAY_WINDOW_MS,
} from "@copilot-mobile/shared";

function startReplayCleanup(): void {
    if (cleanupTimer !== null) return;
    cleanupTimer = setInterval(() => {
        const now = Date.now();
        for (const [id, timestamp] of seenMessageIds) {
            if (now - timestamp > REPLAY_WINDOW_MS) {
                seenMessageIds.delete(id);
            }
        }
    }, REPLAY_CLEANUP_INTERVAL_MS);
    // Timer process'i canlı tutmasın
    cleanupTimer.unref();
}

() => {
        const now = Date.now();
        for (const [id, timestamp] of seenMessageIds) {
            if (now - timestamp > REPLAY_WINDOW_MS) {
                seenMessageIds.delete(id);
            }
        }
    }

function checkLimit(
    windows: Map<string, WindowEntry>,
    key: string,
    maxCount: number,
    windowMs: number
): boolean {
    const now = Date.now();
    let entry = windows.get(key);

    if (entry === undefined) {
        entry = { timestamps: [] };
        windows.set(key, entry);
    }

    // Eski kayıtları temizle
    entry.timestamps = entry.timestamps.filter((t) => now - t < windowMs);

    if (entry.timestamps.length >= maxCount) {
        return false;
    }

    entry.timestamps.push(now);
    return true;
}

function checkPairingRateLimit(ip: string): boolean {
    return checkLimit(
        pairingWindows,
        ip,
        RATE_LIMIT_PAIRING_MAX,
        RATE_LIMIT_PAIRING_WINDOW_MS
    );
}

function checkMessageRateLimit(deviceId: string): boolean {
    return checkLimit(
        messageWindows,
        deviceId,
        RATE_LIMIT_MESSAGE_MAX,
        RATE_LIMIT_MESSAGE_WINDOW_MS
    );
}

function checkReplayProtection(messageId: string): boolean {
    // İlk çağrıda periyodik temizlemeyi başlat
    startReplayCleanup();

    const now = Date.now();

    if (seenMessageIds.has(messageId)) {
        return false;
    }

    seenMessageIds.set(messageId, now);
    return true;
}

function clearRateLimitState(): void {
    pairingWindows.clear();
    messageWindows.clear();
    seenMessageIds.clear();
    if (cleanupTimer !== null) {
        clearInterval(cleanupTimer);
        cleanupTimer = null;
    }
}

