// Uçtan uca test — Gerçek Copilot CLI ile bridge server doğrulaması
// Bu test gerçek bir Copilot CLI oturumu gerektirir (gh auth ile kimlik doğrulanmış olmalı)
// Çalıştırma: node --import tsx tests/e2e/copilot-e2e.test.ts
import { describe, it, before, after } from "node:test";

// Copilot CLI yavaş olabilir
// --- Test Yardımcıları ---
function makeClientMsg(
    type: ClientMessage["type"],
    payload: Record<string, unknown>
): Record<string, unknown> {
    return {
        id: randomUUID(),
        timestamp: Date.now(),
        seq: 1,
