type WSClient = {
    ws: WebSocket;
    messages: ServerMessage[];
    waitForMessage(type: string, timeoutMs?: number): Promise<ServerMessage>;
    send(msg: Record<string, unknown>): void;
    close(): Promise<void>;
};

function connectToServer(port: number, jwtToken?: string): Promise<WSClient> {
    return new Promise((resolve, reject) => {
        const url = jwtToken !== undefined
            ? `wss://127.0.0.1:${port}?token=${encodeURIComponent(jwtToken)}`
            : `wss://127.0.0.1:${port}`;

        const ws = new WebSocket(url, { rejectUnauthorized: false });
        const messages: ServerMessage[] = [];
        const waiters: Array<{
            type: string;
            resolve: (msg: ServerMessage) => void;
            reject: (err: Error) => void;
        }> = [];

        ws.on("message", (data: Buffer) => {
            const msg = JSON.parse(data.toString("utf-8")) as ServerMessage;
            messages.push(msg);

            const idx = waiters.findIndex((w) => w.type === msg.type);
            if (idx !== -1) {
                const waiter = waiters[idx]!;
                waiters.splice(idx, 1);
                waiter.resolve(msg);
            }
        });

        ws.on("open", () => {
            resolve({
                ws,
                messages,

                waitForMessage(type: string, timeoutMs: number = E2E_TIMEOUT): Promise<ServerMessage> {
                    const existing = messages.find((m) => m.type === type);
                    if (existing !== undefined) {
                        return Promise.resolve(existing);
                    }

                    return new Promise((res, rej) => {
                        const timer = setTimeout(() => {
                            const idx = waiters.findIndex((w) => w.type === type);
                            if (idx !== -1) waiters.splice(idx, 1);
                            rej(new Error(`Timeout: ${type} mesajı ${timeoutMs}ms içinde gelmedi`));
                        }, timeoutMs);

                        waiters.push({
                            type,
                            resolve: (msg) => {
                                clearTimeout(timer);
                                res(msg);
                            },
                            reject: rej,
                        });
                    });
                },

                send(msg: Record<string, unknown>): void {
                    ws.send(JSON.stringify(msg));
                },

                close(): Promise<void> {
                    return new Promise((res) => {
                        if (ws.readyState === WebSocket.CLOSED) {
                            res();
                            return;
                        }
                        ws.on("close", () => res());
                        ws.close();
                    });
                },
            });
        });

        ws.on("error", reject);
    });
}

