// Session Manager — Copilot oturumlarını yönetir ve WS mesajlarına dönüştürür
import type {
    AdaptedCopilotClient,
    AdaptedCopilotSession,
    AdaptedPermissionRequest,
    SessionConfig,
    ServerMessage,
} from "@copilot-mobile/shared";

// Chat ve session state yönetimi — Zustand store
// Birleşik ChatItem timeline ile thinking, tool ve mesajlar tek akışta
import { create } from "zustand";

// Sohbet akışındaki öğe tipleri
type ChatItemBase = {
    id: string;
    timestamp: number;
};

type UserMessageItem = ChatItemBase & {
    type: "user";
    content: string;
};

type AssistantMessageItem = ChatItemBase & {
    type: "assistant";
    content: string;
    isStreaming: boolean;
};

type ThinkingItem = ChatItemBase & {
    type: "thinking";
    content: string;
    isExpanded: boolean;
    isStreaming: boolean;
};

type ToolItem = ChatItemBase & {
    type: "tool";
    toolName: string;
    requestId: string;
    status: "running" | "completed" | "failed";
};

type PermissionPrompt = {
    requestId: string;
    kind: string;
    toolName: string | null;
    fileName: string | null;
    commandText: string | null;
};

type UserInputPrompt = {
    requestId: string;
    prompt: string;
};

type SessionStore = {
    // Session
    activeSessionId: string | null;
    isSessionLoading: boolean;
    sessions: ReadonlyArray<SessionInfo>;
    models: ReadonlyArray<ModelInfo>;
    selectedModel: string;
    reasoningEffort: "low" | "medium" | "high" | "xhigh";

    // Birleşik sohbet akışı (mesaj, thinking, tool hepsi tek timeline)
    chatItems: ReadonlyArray<ChatItem>;
    isAssistantTyping: boolean;

    // İzin ve girdi istemleri (modal overlay)
    permissionPrompt: PermissionPrompt | null;
    userInputPrompt: UserInputPrompt | null;

    // Aksiyonlar
    setActiveSession: (sessionId: string | null) => void;
    setSessionLoading: (loading: boolean) => void;
    setSessions: (sessions: ReadonlyArray<SessionInfo>) => void;
    upsertSession: (session: SessionInfo) => void;
    removeSession: (sessionId: string) => void;
    setModels: (models: ReadonlyArray<ModelInfo>) => void;
    setSelectedModel: (model: string) => void;
    setReasoningEffort: (effort: "low" | "medium" | "high" | "xhigh") => void;

    addUserMessage: (content: string) => void;
    appendAssistantDelta: (delta: string) => void;
    finalizeAssistantMessage: (content: string) => void;
    setAssistantTyping: (typing: boolean) => void;

    appendThinkingDelta: (delta: string) => void;
    finalizeThinking: () => void;
    toggleThinkingExpanded: (id: string) => void;

    addToolStart: (requestId: string, toolName: string) => void;
    updateToolStatus: (requestId: string, status: "completed" | "failed") => void;

    setPermissionPrompt: (prompt: PermissionPrompt | null) => void;
    setUserInputPrompt: (prompt: UserInputPrompt | null) => void;

    replaceChatItems: (items: ReadonlyArray<ChatItem>) => void;
    clearChatItems: () => void;
    reset: () => void;
};

